 23Ôćĺconst extractBearerToken = (authHeader = "") => {
 24Ôćĺ    const trimmed = typeof authHeader === "string" ? authHeader.trim() : "";
 25Ôćĺ    if (!trimmed) return "";
 26Ôćĺ
 27Ôćĺ    const bearerMatch = trimmed.match(/^Bearer\s+(.+)$/i);
 28Ôćĺ    if (bearerMatch?.[1]) {
 29Ôćĺ        return bearerMatch[1].trim();
 30Ôćĺ    }
 31Ôćĺ
 32Ôćĺ    return trimmed;
 33Ôćĺ};
