 35Ôćĺconst resolveAuthUser = async (token) => {
 36Ôćĺ    if (!token) {
 37Ôćĺ        return { user: null, error: null };
 38Ôćĺ    }
 39Ôćĺ
 40Ôćĺ    const { data: authData, error: authError } = await supabase.auth.getUser(token);
 41Ôćĺ    if (authError || !authData?.user?.id) {
 42Ôćĺ        return { user: null, error: authError || new Error("missing user id") };
 43Ôćĺ    }
 44Ôćĺ
 45Ôćĺ    return { user: authData.user, error: null };
 46Ôćĺ};
 47Ôćĺ
 48Ôćĺconst requireAuth = async (req, res, next) => {
 49Ôćĺ    const token = extractBearerToken(req.headers?.authorization);
 50Ôćĺ    if (!token) {
 51Ôćĺ        return res.status(401).json({ error: 'not authorized' });
 52Ôćĺ    }
 53Ôćĺ
 54Ôćĺ    const { user, error } = await resolveAuthUser(token);
 55Ôćĺ    if (error || !user?.id) {
 56Ôćĺ        console.error('auth middleware error:', error?.message || 'missing user id');
 57Ôćĺ        return res.status(401).json({ error: 'not authorized' });
 58Ôćĺ    }
 59Ôćĺ
 60Ôćĺ    req.userId = user.id;
 61Ôćĺ    req.authUser = user;
 62Ôćĺ    return next();
 63Ôćĺ};
 64Ôćĺ
 65Ôćĺconst optionalAuth = async (req, _res, next) => {
 66Ôćĺ    const token = extractBearerToken(req.headers?.authorization);
 67Ôćĺ    if (!token) {
 68Ôćĺ        return next();
 69Ôćĺ    }
 70Ôćĺ
 71Ôćĺ    const { user } = await resolveAuthUser(token);
 72Ôćĺ    if (user?.id) {
 73Ôćĺ        req.userId = user.id;
 74Ôćĺ        req.authUser = user;
 75Ôćĺ    }
 76Ôćĺ
 77Ôćĺ    return next();
 78Ôćĺ};
